/**
 * Model User
 * Base user account — shared by Students, Instructors, and Admins.
 * Passwords hashed with Argon2. Email must be verified before booking.
 */
export type User = $Result.DefaultSelection<Prisma.$UserPayload>
/**
 * Model InstructorProfile
 * Extended profile for Instructors.
 * Must be admin-approved before appearing in public search results.
 * avgRating and totalReviews are denormalized for fast search.
 */
export type InstructorProfile = $Result.DefaultSelection<Prisma.$InstructorProfilePayload>
/**
 * Model InstructorLocation
 * Instructor service area location.
 * Indexed for geo-proximity search and city filtering.
 */
export type InstructorLocation = $Result.DefaultSelection<Prisma.$InstructorLocationPayload>
/**
 * Model Booking
 * A booked driving lesson between a Student and Instructor.
 * Ownership is enforced on every action — students see only theirs,
 * instructors see only theirs.
 */
export type Booking = $Result.DefaultSelection<Prisma.$BookingPayload>
/**
 * Model Payment
 * Payment record linked to Stripe Payment Intents.
 * We NEVER store card numbers — only Stripe identifiers.
 */
export type Payment = $Result.DefaultSelection<Prisma.$PaymentPayload>
/**
 * Model Review
 * Student review of an instructor after a COMPLETED booking.
 * One review per booking (unique constraint). Rating validated 1–5.
 */
export type Review = $Result.DefaultSelection<Prisma.$ReviewPayload>
/**
 * Model AuditLog
 * Immutable audit log for security-sensitive operations.
 * Append-only — never deleted.
 */
export type AuditLog = $Result.DefaultSelection<Prisma.$AuditLogPayload>

